import{c as n,Q as t,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"Harness Engineering: Leveraging Codex in an Agent-First World","description":"","frontmatter":{"url":"https://openai.com/index/harness-engineering/","title":"Harness Engineering: Leveraging Codex in an Agent-First World","date":"2026-02-11T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-02-11-openai-harness-engineering-codex.md","filePath":"research/ai-articles/scored/2026-02-11-openai-harness-engineering-codex.md","lastUpdated":1779796674000}'),s={name:"research/ai-articles/scored/2026-02-11-openai-harness-engineering-codex.md"};function i(o,e,l,d,g,p){return t(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="harness-engineering-leveraging-codex-in-an-agent-first-world" tabindex="-1">Harness Engineering: Leveraging Codex in an Agent-First World <a class="header-anchor" href="#harness-engineering-leveraging-codex-in-an-agent-first-world" aria-label="Permalink to &quot;Harness Engineering: Leveraging Codex in an Agent-First World&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://openai.com/index/harness-engineering/" target="_blank" rel="noreferrer">https://openai.com/index/harness-engineering/</a><br><strong>作者</strong>：Ryan Lopopolo（OpenAI Member of Technical Staff）<br><strong>發表日期</strong>：2026-02-11<br><strong>評分日期</strong>：2026-05-05</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="核心命題" tabindex="-1">核心命題 <a class="header-anchor" href="#核心命題" aria-label="Permalink to &quot;核心命題&quot;">​</a></h3><p>OpenAI 內部實驗：以 3 位工程師（後擴至 7 位）驅動 Codex Agents，在 5 個月內用 <strong>零行手寫代碼</strong> 建立並部署了一個擁有 <strong>百萬行代碼</strong> 的真實內部產品，開出 ~1,500 個 PR，吞吐量達每位工程師每天 3.5 個 PR。</p><p><strong>核心哲學</strong>：人類掌舵（設計、規格、驗收）；Agent 執行（寫碼、測試、PR、review、merge）。</p><h3 id="工程師角色的重新定義" tabindex="-1">工程師角色的重新定義 <a class="header-anchor" href="#工程師角色的重新定義" aria-label="Permalink to &quot;工程師角色的重新定義&quot;">​</a></h3><p>傳統角色 → Agent-first 角色的轉變：</p><ul><li><strong>傳統</strong>：直接撰寫代碼</li><li><strong>Agent-first</strong>：設計環境、指定意圖、建立反饋循環</li></ul><p>當 Agent 失敗時，問題從不是「再試一次」，而是：「<strong>缺少什麼能力？如何讓這個能力對 Agent 可見且可執行？</strong>」</p><h3 id="知識庫設計-把-agents-md-當目錄-不是手冊" tabindex="-1">知識庫設計：把 AGENTS.md 當目錄，不是手冊 <a class="header-anchor" href="#知識庫設計-把-agents-md-當目錄-不是手冊" aria-label="Permalink to &quot;知識庫設計：把 AGENTS.md 當目錄，不是手冊&quot;">​</a></h3><p>最重要的架構決策之一：<strong>短 AGENTS.md（約 100 行）作為 table of contents，真正的知識住在結構化 docs/ 目錄</strong>。</p><p>失敗的「一個大 AGENTS.md」的四個問題：</p><ol><li><strong>Context 是稀缺資源</strong>：一個巨大指令檔案擠壓了任務、代碼和相關文件</li><li><strong>過多指引變成無指引</strong>：當一切都「重要」，就沒有什麼重要</li><li><strong>立即過時</strong>：單體手冊變成陳舊規則的墓地</li><li><strong>無法機械驗證</strong>：無法進行覆蓋率、新鮮度、交叉連結等檢查</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AGENTS.md（100 行 map）</span></span>
<span class="line"><span>ARCHITECTURE.md</span></span>
<span class="line"><span>docs/</span></span>
<span class="line"><span>├── design-docs/（索引 + 核心信念）</span></span>
<span class="line"><span>├── exec-plans/（active/ completed/ 技術債追蹤）</span></span>
<span class="line"><span>├── generated/（db-schema.md）</span></span>
<span class="line"><span>├── product-specs/</span></span>
<span class="line"><span>└── references/（llms.txt 格式）</span></span></code></pre></div><h3 id="應用程式可讀性-application-legibility" tabindex="-1">應用程式可讀性（Application Legibility） <a class="header-anchor" href="#應用程式可讀性-application-legibility" aria-label="Permalink to &quot;應用程式可讀性（Application Legibility）&quot;">​</a></h3><p>讓 Codex 可以直接與應用程式互動：</p><ul><li><strong>每個 git worktree 可啟動獨立 app 實例</strong>：Codex 可並行處理多個變更</li><li><strong>Chrome DevTools Protocol 整合</strong>：Codex 可截圖、觀察 DOM、驗證 UI 行為</li><li><strong>本地 observability stack（Victoria Logs/Metrics）</strong>：讓「確保 API 在 800ms 內完成」這樣的指令可執行</li></ul><p>Codex 可以在 agent 不間斷運行長達 <strong>6 小時</strong>（通常在工程師睡覺時）。</p><h3 id="架構強制執行-黃金原則" tabindex="-1">架構強制執行：黃金原則 <a class="header-anchor" href="#架構強制執行-黃金原則" aria-label="Permalink to &quot;架構強制執行：黃金原則&quot;">​</a></h3><p>不微管理實作方式，但強制執行不變量（invariants）：</p><ul><li>每個業務領域有固定層次（Types → Config → Repo → Service → Runtime → UI）</li><li>嚴格的依賴方向，由自定義 linter 機械性執行</li><li>Cross-cutting concerns（auth、telemetry）透過 Providers 單一介面進入</li></ul><p><strong>Agent-first 時代的架構規律</strong>：在人類主導的工作流中，這些規則顯得迂腐；但在 Agent 主導時，它們是速度不衰減的倍增器。</p><h3 id="垃圾回收機制-entropy-management" tabindex="-1">垃圾回收機制（Entropy Management） <a class="header-anchor" href="#垃圾回收機制-entropy-management" aria-label="Permalink to &quot;垃圾回收機制（Entropy Management）&quot;">​</a></h3><p>Agent 複製現有模式，包括不良模式，最終導致漂移（drift）：</p><ul><li><strong>以前</strong>：每週五花 20% 的時間清理「AI slop」，無法擴展</li><li><strong>現在</strong>：Golden Principles 寫入 repo，定期 background Codex 任務掃描偏差、更新品質分數、開 refactoring PR</li></ul><p>「技術債是高利率貸款：持續小增量還債遠比讓它複利然後痛苦清算更好。」</p><h3 id="全自動化端到端能力" tabindex="-1">全自動化端到端能力 <a class="header-anchor" href="#全自動化端到端能力" aria-label="Permalink to &quot;全自動化端到端能力&quot;">​</a></h3><p>成熟後，一個提示詞可讓 Codex 完成：</p><ol><li>驗證當前代碼庫狀態</li><li>重現回報的 bug，錄製影片</li><li>實作修復，再錄影片驗證</li><li>開 PR，回應 agent/human 反饋</li><li>偵測並修復 build 失敗</li><li>只在需要人類判斷時才上升報告</li><li>合併</li></ol><h3 id="對-workspace-的啟示" tabindex="-1">對 Workspace 的啟示 <a class="header-anchor" href="#對-workspace-的啟示" aria-label="Permalink to &quot;對 Workspace 的啟示&quot;">​</a></h3><ol><li><strong>AGENTS.md 作為目錄</strong>：cc-workspace 的 CLAUDE.md 應保持精簡（100 行內），詳細規則用 @-import 按需載入，與本文發現完全一致。</li><li><strong>知識必須住在 repo</strong>：Slack 討論、口頭約定對 Agent 不可見 = 不存在。所有架構決策應提煉為 markdown（docs/、<code>.claude/refs/</code>）。</li><li><strong>黃金原則 + 機械性執行</strong>：linter rules、pre-commit hooks 是 Agent 的護欄，比口頭指令更可靠。</li><li><strong>Progressive disclosure</strong>：docs/ 分層索引、skills 按需載入 — 這正是 cc-workspace 的設計。</li></ol><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>AGENTS.md 目錄化、docs/ 知識庫設計、垃圾回收機制均直接可套用</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>零手寫代碼的完整工程實驗，「知識必須住在 repo」的認識論突破</td></tr><tr><td>C. 證據品質</td><td>9/10</td><td>真實產品，百萬行代碼，1,500 PR，數百內部用戶，5 個月實驗</td></tr><tr><td>D. 技術深度</td><td>9/10</td><td>架構圖、層次設計、linter 機制、observability stack 均有詳細說明</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>核心模式（精簡 AGENTS.md、層次化 docs、機械性約束）普遍適用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.65/10</strong></td><td>9×0.3 + 8×0.2 + 9×0.2 + 9×0.15 + 8×0.15 = 2.7+1.6+1.8+1.35+1.2</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/rules/core.md</code> 或 <code>.claude/refs/anthropic-insights.md</code><br><strong>整合狀態</strong>：待實作</p><p><strong>TODO</strong>：</p><ul><li>在 CLAUDE.md 中強化「AGENTS.md 作為目錄」的明確說明</li><li>參考 Golden Principles 概念，將「黃金不變量」加入 core.md 的「外科刀式修改」章節</li><li>考慮建立 doc-gardening 型 Agent（定期掃描過時文件）</li></ul>`,39)])])}const m=n(s,[["render",i]]);export{h as __pageData,m as default};
